    <title>Portfolio - CAMARA IBRAHIM | BTS SIO SLAM</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap" rel="stylesheet">
    <style>
        body {
            font-family: 'Inter', sans-serif;
            scroll-behavior: smooth;
        }
        
        /* Couleurs inspirées de la photo de profil */
        :root {
            --primary-purple: #8b5cf6;
            --primary-blue: #3b82f6;
            --primary-pink: #ec4899;
            --dark-bg: #1e1b4b;
            --light-purple: #f3e8ff;
        }
        
        /* Header fixe élégant */
        header {
            background: rgba(255, 255, 255, 0.98);
            backdrop-filter: blur(10px);
            border-bottom: 2px solid var(--primary-purple);
            box-shadow: 0 2px 10px rgba(139, 92, 246, 0.1);
        }
        
        /* Navigation */
        nav a {
            position: relative;
            transition: all 0.3s ease;
        }
        
        nav a::after {
            content: '';
            position: absolute;
            bottom: -2px;
            left: 0;
            width: 0;
            height: 2px;
            background: linear-gradient(90deg, var(--primary-purple), var(--primary-blue));
            transition: width 0.3s ease;
        }
        
        nav a:hover::after {
            width: 100%;
        }
        
        /* Section Hero avec dégradé */
        .hero-gradient {
            background: linear-gradient(135deg, #f3e8ff 0%, #ddd6fe 50%, #e9d5ff 100%);
        }
        
        /* Sections avec couleurs alternées */
        .section-purple {
            background: linear-gradient(135deg, #faf5ff 0%, #f3e8ff 100%);
        }
        
        .section-blue {
            background: linear-gradient(135deg, #eff6ff 0%, #dbeafe 100%);
        }
        
        .section-pink {
            background: linear-gradient(135deg, #fdf2f8 0%, #fce7f3 100%);
        }
        
        /* Cartes élégantes */
        .card {
            background: white;
            border-radius: 16px;
            box-shadow: 0 4px 6px rgba(0, 0, 0, 0.07);
            transition: all 0.3s ease;
            border: 1px solid rgba(139, 92, 246, 0.1);
        }
        
        .card:hover {
            transform: translateY(-5px);
            box-shadow: 0 10px 20px rgba(139, 92, 246, 0.15);
            border-color: var(--primary-purple);
        }
        
        /* Photo de profil */
        .profile-photo {
            border: 4px solid var(--primary-purple);
            box-shadow: 0 10px 30px rgba(139, 92, 246, 0.3);
            transition: transform 0.3s ease;
            border-radius: 50%;
            width: 280px;
            height: 280px;
            object-fit: cover;
        }
        
        .profile-photo:hover {
            transform: scale(1.05);
        }
        
        /* Timeline */
        .timeline-item {
            position: relative;
            padding-left: 40px;
            padding-bottom: 30px;
        }
        
        .timeline-item:last-child {
            padding-bottom: 0;
        }
        
        .timeline-item::before {
            content: '';
            position: absolute;
            left: 15px;
            top: 0;
            bottom: 0;
            width: 2px;
            background: linear-gradient(to bottom, var(--primary-purple), var(--primary-blue));
        }
        
        .timeline-item:last-child::before {
            display: none;
        }
        
        .timeline-dot {
            position: absolute;
            left: 8px;
            top: 8px;
            width: 16px;
            height: 16px;
            border-radius: 50%;
            background: white;
            border: 3px solid var(--primary-purple);
            box-shadow: 0 0 0 4px rgba(139, 92, 246, 0.2);
            z-index: 1;
        }
        
        /* Logos tech */
        .tech-card {
            background: white;
            border-radius: 12px;
            padding: 24px;
            text-align: center;
            box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
            transition: all 0.3s ease;
            border: 1px solid rgba(139, 92, 246, 0.1);
        }
        
        .tech-card:hover {
            transform: translateY(-8px);
            box-shadow: 0 8px 20px rgba(139, 92, 246, 0.2);
            border-color: var(--primary-purple);
        }
        
        .tech-card i {
            font-size: 3.5rem;
            margin-bottom: 12px;
        }
        
        /* Titres de sections */
        .section-title {
            font-size: 2.5rem;
            font-weight: 800;
            background: linear-gradient(135deg, var(--primary-purple), var(--primary-blue));
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
        }
        
        /* Boutons */
        .btn-primary {
            background: linear-gradient(135deg, var(--primary-purple), var(--primary-blue));
            color: white;
            padding: 12px 32px;
            border-radius: 8px;
            font-weight: 600;
            transition: all 0.3s ease;
            box-shadow: 0 4px 12px rgba(139, 92, 246, 0.3);
        }
        
        .btn-primary:hover {
            transform: translateY(-2px);
            box-shadow: 0 6px 20px rgba(139, 92, 246, 0.4);
        }
        
        /* Badge */
        .badge {
            background: linear-gradient(135deg, rgba(139, 92, 246, 0.1), rgba(59, 130, 246, 0.1));
            border: 1px solid var(--primary-purple);
            color: var(--primary-purple);
            padding: 6px 16px;
            border-radius: 20px;
            font-size: 0.875rem;
            font-weight: 600;
        }
        
        /* Footer */
        footer {
            background: linear-gradient(135deg, #1e1b4b 0%, #312e81 100%);
        }
    </style>
</head>
