<script data-cfasync="false" src="/cdn-cgi/scripts/5c5dd728/cloudflare-static/email-decode.min.js"></script><script>
    // Menu mobile
    document.getElementById('mobile-menu-button').addEventListener('click', function() {
        document.getElementById('mobile-menu').classList.toggle('hidden');
    });
    
    // Fermer menu mobile au clic sur lien
    document.querySelectorAll('#mobile-menu a').forEach(link => {
        link.addEventListener('click', () => {
            document.getElementById('mobile-menu').classList.add('hidden');
        });
    });
    
    // Onglets certifications
    const certTabs = document.querySelectorAll('.cert-tab');
    const certPanels = document.querySelectorAll('.cert-panel');
    
    certTabs.forEach(tab => {
        tab.addEventListener('click', () => {
            // Retirer active de tous
            certTabs.forEach(t => t.classList.remove('active', 'bg-purple-600', 'text-white'));
            certPanels.forEach(p => p.classList.remove('active'));
            
            // Ajouter active au cliqué
            tab.classList.add('active', 'bg-purple-600', 'text-white');
            const targetId = tab.getAttribute('data-target');
            document.getElementById(targetId).classList.add('active');
        });
    });
    
    // Styles dynamiques pour onglets
    document.querySelectorAll('.cert-tab').forEach(tab => {
        if (!tab.classList.contains('active')) {
            tab.classList.add('bg-gray-200', 'text-gray-700', 'hover:bg-gray